import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import toast from 'react-hot-toast';
import api from '../../utils/api';

const CATEGORIES = ['Conference', 'Workshop', 'Concert', 'Sports', 'Festival', 'Networking', 'Exhibition', 'Webinar', 'Other'];

const defaultForm = {
  title: '', description: '', category: 'Conference',
  date: '', time: '', endTime: '',
  location: { venue: '', address: '', city: '', state: '', country: 'India' },
  price: 0, totalSeats: 100,
  image: '', tags: '', featured: false, status: 'upcoming'
};

export default function CreateEditEvent() {
  const { id } = useParams();
  const navigate = useNavigate();
  const isEdit = Boolean(id);
  const [form, setForm] = useState(defaultForm);
  const [loading, setLoading] = useState(false);
  const [fetching, setFetching] = useState(isEdit);

  useEffect(() => {
    if (isEdit) {
      api.get(`/events/${id}`).then(({ data }) => {
        const e = data.event;
        setForm({
          title: e.title || '', description: e.description || '', category: e.category || 'Conference',
          date: e.date ? e.date.split('T')[0] : '', time: e.time || '', endTime: e.endTime || '',
          location: { venue: e.location?.venue || '', address: e.location?.address || '', city: e.location?.city || '', state: e.location?.state || '', country: e.location?.country || 'India' },
          price: e.price || 0, totalSeats: e.totalSeats || 100,
          image: e.image || '', tags: e.tags?.join(', ') || '', featured: e.featured || false, status: e.status || 'upcoming'
        });
      }).catch(() => { toast.error('Event not found'); navigate('/admin/events'); })
      .finally(() => setFetching(false));
    }
  }, [id, isEdit, navigate]);

  const update = (key) => (e) => setForm(f => ({ ...f, [key]: e.target.type === 'checkbox' ? e.target.checked : e.target.value }));
  const updateLoc = (key) => (e) => setForm(f => ({ ...f, location: { ...f.location, [key]: e.target.value } }));

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const payload = {
        ...form,
        price: Number(form.price),
        totalSeats: Number(form.totalSeats),
        tags: form.tags ? form.tags.split(',').map(t => t.trim()).filter(Boolean) : []
      };

      if (isEdit) {
        await api.put(`/admin/events/${id}`, payload);
        toast.success('Event updated successfully!');
      } else {
        await api.post('/admin/events', payload);
        toast.success('Event created successfully!');
      }
      navigate('/admin/events');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to save event');
    } finally {
      setLoading(false);
    }
  };

  if (fetching) return <div className="spinner" style={{ marginTop: 120 }} />;

  const Section = ({ title, children }) => (
    <div style={{ background: '#1a2235', border: '1px solid #1e293b', borderRadius: 16, padding: 28, marginBottom: 20 }}>
      <h2 style={{ fontFamily: 'Playfair Display', fontSize: 20, marginBottom: 20, paddingBottom: 14, borderBottom: '1px solid #1e293b' }}>{title}</h2>
      {children}
    </div>
  );

  return (
    <div style={{ paddingTop: 90, minHeight: '100vh' }}>
      <div className="container" style={{ padding: '40px 24px', maxWidth: 840 }}>
        <div style={{ marginBottom: 32 }}>
          <h1 style={{ fontFamily: 'Playfair Display', fontSize: 36, marginBottom: 8 }}>{isEdit ? 'Edit Event' : 'Create New Event'}</h1>
          <p style={{ color: '#94a3b8' }}>{isEdit ? `Editing event ID: ${id}` : 'Fill in the details to publish a new event'}</p>
        </div>

        <form onSubmit={handleSubmit}>
          <Section title="Basic Information">
            <div className="form-group">
              <label>Event Title *</label>
              <input className="form-control" required placeholder="e.g. Tech Summit 2025" value={form.title} onChange={update('title')} />
            </div>
            <div className="form-group">
              <label>Description *</label>
              <textarea className="form-control" required rows={5} placeholder="Describe the event in detail..." value={form.description} onChange={update('description')} />
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
              <div className="form-group">
                <label>Category *</label>
                <select className="form-control" value={form.category} onChange={update('category')}>
                  {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>
              <div className="form-group">
                <label>Status</label>
                <select className="form-control" value={form.status} onChange={update('status')}>
                  <option value="upcoming">Upcoming</option>
                  <option value="ongoing">Ongoing</option>
                  <option value="completed">Completed</option>
                  <option value="cancelled">Cancelled</option>
                </select>
              </div>
            </div>
            <div className="form-group">
              <label>Image URL (optional)</label>
              <input className="form-control" type="url" placeholder="https://..." value={form.image} onChange={update('image')} />
            </div>
            <div className="form-group">
              <label>Tags (comma-separated)</label>
              <input className="form-control" placeholder="technology, AI, innovation" value={form.tags} onChange={update('tags')} />
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
              <input type="checkbox" id="featured" checked={form.featured} onChange={update('featured')} style={{ width: 16, height: 16, accentColor: '#f59e0b', cursor: 'pointer' }} />
              <label htmlFor="featured" style={{ cursor: 'pointer', color: '#94a3b8', fontSize: 14 }}>⭐ Mark as Featured Event</label>
            </div>
          </Section>

          <Section title="Date & Time">
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 16 }}>
              <div className="form-group">
                <label>Date *</label>
                <input className="form-control" type="date" required value={form.date} onChange={update('date')} />
              </div>
              <div className="form-group">
                <label>Start Time *</label>
                <input className="form-control" type="time" required value={form.time} onChange={update('time')} />
              </div>
              <div className="form-group">
                <label>End Time</label>
                <input className="form-control" type="time" value={form.endTime} onChange={update('endTime')} />
              </div>
            </div>
          </Section>

          <Section title="Location">
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
              <div className="form-group">
                <label>Venue Name *</label>
                <input className="form-control" required placeholder="e.g. Bombay Exhibition Centre" value={form.location.venue} onChange={updateLoc('venue')} />
              </div>
              <div className="form-group">
                <label>City *</label>
                <input className="form-control" required placeholder="e.g. Mumbai" value={form.location.city} onChange={updateLoc('city')} />
              </div>
            </div>
            <div className="form-group">
              <label>Full Address *</label>
              <input className="form-control" required placeholder="Street, locality..." value={form.location.address} onChange={updateLoc('address')} />
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
              <div className="form-group">
                <label>State</label>
                <input className="form-control" placeholder="Maharashtra" value={form.location.state} onChange={updateLoc('state')} />
              </div>
              <div className="form-group">
                <label>Country</label>
                <input className="form-control" value={form.location.country} onChange={updateLoc('country')} />
              </div>
            </div>
          </Section>

          <Section title="Tickets & Pricing">
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
              <div className="form-group">
                <label>Price (₹) — Set 0 for Free</label>
                <input className="form-control" type="number" min="0" value={form.price} onChange={update('price')} />
              </div>
              <div className="form-group">
                <label>Total Seats *</label>
                <input className="form-control" type="number" min="1" required value={form.totalSeats} onChange={update('totalSeats')} />
              </div>
            </div>
          </Section>

          <div style={{ display: 'flex', gap: 12, justifyContent: 'flex-end' }}>
            <button type="button" className="btn btn-ghost" onClick={() => navigate('/admin/events')}>Cancel</button>
            <button type="submit" className="btn btn-primary btn-lg" disabled={loading}>
              {loading ? 'Saving...' : isEdit ? 'Update Event' : 'Create Event'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
